import Accordion from '@/components/Accordion';
import {
  Table,
  TableBody,
  TableCaption,
  TableCell,
  TableHead,
  TableHeader,
  TableRow
} from '@/components/ui/table';
import Technology from '@/types/Technology';
import { Terminal } from 'lucide-react';
import Image from 'next/image';
import AccordionButtons from './components/AccordionItems/AccordionButtons';

export default async function AdminPage() {
  async function fetchTechnologies() {
    const response = await fetch(`${process.env.API_URL}/technologies`, {
      cache: 'force-cache'
    });
    const data = await response.json();
    return data;
  }
  const data = await fetchTechnologies();
  const technologies: Technology[] = data.data;

  return (
    <>
      <section className="relative flex h-screen flex-col items-center py-6 text-white lg:p-16">
        <h1 className="mb-5 flex items-center gap-4">
          <span className="animate-pulse">
            <Terminal style={{ color: 'var(--color-primary)' }} size={40} />
          </span>
          OLÁ JOEL!
        </h1>
        <section className="w-full">
          
          <Table className="justify-self-center text-gray dark:text-white w-7/10">
            <TableCaption>Lista de Tecnologias</TableCaption>
            <TableHeader >
              <TableHead className='text-start'>Logo</TableHead>
              <TableHead className='text-center'>Nome</TableHead>
              <TableHead className='text-right'>Opções</TableHead>
            </TableHeader>
            <TableBody>
              {technologies.map((technology) => (
                <TableRow key={technology.id}>
                  <TableCell className="w-[100px] text-center">
                    <Image
                      src={technology.logo.imageLink}
                      alt={technology.name + ' logo'}
                      width={25}
                      height={25}
                    />
                  </TableCell>
                  <TableCell className="text-center text-lg">
                    {technology.name}
                  </TableCell>
                  <TableCell className="text-center">
                    <AccordionButtons identifier={technology.id} />
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
            <Accordion>
              <Form action={createTechnologyAction}>
                <Label htmlFor="technologyName">Nome da Tecnologia</Label>
                <Input name="technology" id="technologyName" type="text" />
                <Label htmlFor="technologyImageName">Nome da imagem</Label>
                <Input
                  name="technologyImageName"
                  id="technologyImageName"
                  type="text"
                />
                <Label htmlFor="technologyImageLink">Link da imagem</Label>
                <Input
                  name="technologyImageLink"
                  id="technologyImageLink"
                  type="text"
                />
              </Form>
            </Accordion>
          </Table>
        </section>
      </section>
    </>
  );
}
